{% raw %}
<div class="game-container">
  <div class="game-header">
    <h1>🎯 2048</h1>
    <div class="game-controls">
      <button id="newGameBtn" onclick="newGame()">新游戏</button>
    </div>
    <div class="game-info">
      <div class="score">得分: <span id="score">0</span></div>
      <div class="high-score">最高分: <span id="highScore">0</span></div>
    </div>
  </div>

  <div class="game-board-container">
    <div id="gameBoard" class="game-board"></div>
    <div id="gameOver" class="game-over hidden">
      <h2>游戏结束!</h2>
      <p>得分: <span id="finalScore">0</span></p>
      <button onclick="newGame()">再来一局</button>
    </div>
    <div id="gameWin" class="game-win hidden">
      <h2>🎉 恭喜!</h2>
      <p>你达到了2048!</p>
      <button onclick="continueGame()">继续游戏</button>
      <button onclick="newGame()">新游戏</button>
    </div>
  </div>

  <div class="game-instructions">
    <h3>游戏说明</h3>
    <ul>
      <li>使用方向键或 WASD 移动所有方块</li>
      <li>相同数字的方块会合并成更大的数字</li>
      <li>目标是合并出2048方块</li>
      <li>无法移动时游戏结束</li>
    </ul>
  </div>
</div>

<style>
  .game-container {
    max-width: 600px;
    margin: 0 auto;
    padding: 20px;
    text-align: center;
  }

  .game-header h1 {
    font-size: 2.5em;
    margin-bottom: 20px;
  }

  .game-controls {
    margin: 20px 0;
  }

  .game-controls button {
    padding: 10px 20px;
    margin: 0 10px;
    font-size: 16px;
    cursor: pointer;
    background: var(--theme, #3498db);
    color: white;
    border: none;
    border-radius: 5px;
    transition: all 0.3s;
  }

  .game-controls button:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 8px rgba(0,0,0,0.2);
  }

  .game-info {
    display: flex;
    justify-content: center;
    gap: 30px;
    margin: 20px 0;
    font-size: 18px;
  }

  .game-board-container {
    position: relative;
    display: inline-block;
    margin: 20px 0;
  }

  .game-board {
    display: grid;
    grid-template-columns: repeat(4, 100px);
    grid-template-rows: repeat(4, 100px);
    gap: 10px;
    background: #bbada0;
    padding: 10px;
    border-radius: 10px;
  }

  .tile {
    width: 100px;
    height: 100px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 32px;
    font-weight: bold;
    border-radius: 5px;
    transition: all 0.15s ease;
  }

  .tile-0 { background: rgba(238, 228, 218, 0.35); }
  .tile-2 { background: #eee4da; color: #776e65; }
  .tile-4 { background: #ede0c8; color: #776e65; }
  .tile-8 { background: #f2b179; color: #f9f6f2; }
  .tile-16 { background: #f59563; color: #f9f6f2; }
  .tile-32 { background: #f67c5f; color: #f9f6f2; }
  .tile-64 { background: #f65e3b; color: #f9f6f2; }
  .tile-128 { background: #edcf72; color: #f9f6f2; font-size: 28px; }
  .tile-256 { background: #edcc61; color: #f9f6f2; font-size: 28px; }
  .tile-512 { background: #edc850; color: #f9f6f2; font-size: 28px; }
  .tile-1024 { background: #edc53f; color: #f9f6f2; font-size: 24px; }
  .tile-2048 { background: #edc22e; color: #f9f6f2; font-size: 24px; }
  .tile-super { background: #3c3a32; color: #f9f6f2; font-size: 20px; }

  .game-over, .game-win {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(238, 228, 218, 0.95);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    border-radius: 10px;
  }

  .game-over.hidden, .game-win.hidden {
    display: none;
  }

  .game-over h2, .game-win h2 {
    font-size: 2em;
    margin-bottom: 20px;
    color: #776e65;
  }

  .game-over p, .game-win p {
    font-size: 1.2em;
    margin-bottom: 20px;
    color: #776e65;
  }

  .game-over button, .game-win button {
    margin: 5px;
    padding: 10px 20px;
    font-size: 16px;
    cursor: pointer;
    background: #8f7a66;
    color: white;
    border: none;
    border-radius: 5px;
  }

  .game-instructions {
    margin-top: 30px;
    text-align: left;
    padding: 20px;
    background: var(--block, #f5f5f5);
    border-radius: 10px;
  }

  .game-instructions h3 {
    margin-bottom: 15px;
  }

  .game-instructions ul {
    list-style: none;
    padding: 0;
  }

  .game-instructions li {
    padding: 8px 0;
    padding-left: 20px;
    position: relative;
  }

  .game-instructions li:before {
    content: "•";
    position: absolute;
    left: 0;
    color: var(--theme, #3498db);
  }
</style>

<script>
  let board = [];
  let score = 0;
  let highScore = localStorage.getItem('2048HighScore') || 0;
  let gameOver = false;
  let won = false;
  let continueAfterWin = false;

  document.getElementById('highScore').textContent = highScore;

  function initBoard() {
    board = [];
    for (let i = 0; i < 4; i++) {
      board[i] = [];
      for (let j = 0; j < 4; j++) {
        board[i][j] = 0;
      }
    }
  }

  function addRandomTile() {
    const emptyCells = [];
    for (let i = 0; i < 4; i++) {
      for (let j = 0; j < 4; j++) {
        if (board[i][j] === 0) {
          emptyCells.push({ r: i, c: j });
        }
      }
    }

    if (emptyCells.length > 0) {
      const randomCell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
      board[randomCell.r][randomCell.c] = Math.random() < 0.9 ? 2 : 4;
    }
  }

  function renderBoard() {
    const gameBoard = document.getElementById('gameBoard');
    gameBoard.innerHTML = '';

    for (let i = 0; i < 4; i++) {
      for (let j = 0; j < 4; j++) {
        const tile = document.createElement('div');
        const value = board[i][j];
        tile.className = `tile tile-${value > 2048 ? 'super' : value}`;
        tile.textContent = value || '';
        gameBoard.appendChild(tile);
      }
    }
  }

  function slide(row) {
    let arr = row.filter(val => val);
    let missing = 4 - arr.length;
    let zeros = Array(missing).fill(0);
    return zeros.concat(arr);
  }

  function combine(row) {
    for (let i = 3; i > 0; i--) {
      if (row[i] === row[i - 1] && row[i] !== 0) {
        row[i] *= 2;
        score += row[i];
        row[i - 1] = 0;

        if (row[i] === 2048 && !continueAfterWin) {
          won = true;
        }
      }
    }
    return row;
  }

  function moveRight() {
    let moved = false;
    for (let i = 0; i < 4; i++) {
      let row = board[i].slice();
      row = slide(row);
      row = combine(row);
      row = slide(row);

      if (row.join(',') !== board[i].join(',')) {
        moved = true;
      }
      board[i] = row;
    }
    return moved;
  }

  function moveLeft() {
    let moved = false;
    for (let i = 0; i < 4; i++) {
      let row = board[i].slice().reverse();
      row = slide(row);
      row = combine(row);
      row = slide(row);
      row.reverse();

      if (row.join(',') !== board[i].join(',')) {
        moved = true;
      }
      board[i] = row;
    }
    return moved;
  }

  function moveUp() {
    let moved = false;
    for (let j = 0; j < 4; j++) {
      let col = [];
      for (let i = 0; i < 4; i++) {
        col.push(board[i][j]);
      }

      let original = col.join(',');
      col.reverse();
      col = slide(col);
      col = combine(col);
      col = slide(col);
      col.reverse();

      if (col.join(',') !== original) {
        moved = true;
      }

      for (let i = 0; i < 4; i++) {
        board[i][j] = col[i];
      }
    }
    return moved;
  }

  function moveDown() {
    let moved = false;
    for (let j = 0; j < 4; j++) {
      let col = [];
      for (let i = 0; i < 4; i++) {
        col.push(board[i][j]);
      }

      let original = col.join(',');
      col = slide(col);
      col = combine(col);
      col = slide(col);

      if (col.join(',') !== original) {
        moved = true;
      }

      for (let i = 0; i < 4; i++) {
        board[i][j] = col[i];
      }
    }
    return moved;
  }

  function checkGameOver() {
    for (let i = 0; i < 4; i++) {
      for (let j = 0; j < 4; j++) {
        if (board[i][j] === 0) {
          return false;
        }

        if (i < 3 && board[i][j] === board[i + 1][j]) {
          return false;
        }

        if (j < 3 && board[i][j] === board[i][j + 1]) {
          return false;
        }
      }
    }
    return true;
  }

  function updateScore() {
    document.getElementById('score').textContent = score;

    if (score > highScore) {
      highScore = score;
      document.getElementById('highScore').textContent = highScore;
      localStorage.setItem('2048HighScore', highScore);
    }
  }

  function newGame() {
    initBoard();
    score = 0;
    gameOver = false;
    won = false;
    continueAfterWin = false;

    document.getElementById('score').textContent = score;
    document.getElementById('gameOver').classList.add('hidden');
    document.getElementById('gameWin').classList.add('hidden');

    addRandomTile();
    addRandomTile();
    renderBoard();
  }

  function continueGame() {
    continueAfterWin = true;
    document.getElementById('gameWin').classList.add('hidden');
  }

  function handleMove(direction) {
    if (gameOver) return;

    let moved = false;

    switch(direction) {
      case 'up':
        moved = moveUp();
        break;
      case 'down':
        moved = moveDown();
        break;
      case 'left':
        moved = moveLeft();
        break;
      case 'right':
        moved = moveRight();
        break;
    }

    if (moved) {
      addRandomTile();
      renderBoard();
      updateScore();

      if (won && !continueAfterWin) {
        document.getElementById('gameWin').classList.remove('hidden');
      } else if (checkGameOver()) {
        gameOver = true;
        document.getElementById('finalScore').textContent = score;
        document.getElementById('gameOver').classList.remove('hidden');
      }
    }
  }

  document.addEventListener('keydown', (e) => {
    if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
      e.preventDefault();
    }

    switch(e.key) {
      case 'ArrowUp':
      case 'w':
      case 'W':
        handleMove('up');
        break;
      case 'ArrowDown':
      case 's':
      case 'S':
        handleMove('down');
        break;
      case 'ArrowLeft':
      case 'a':
      case 'A':
        handleMove('left');
        break;
      case 'ArrowRight':
      case 'd':
      case 'D':
        handleMove('right');
        break;
    }
  });

  // 触摸支持
  let touchStartX = 0;
  let touchStartY = 0;

  document.addEventListener('touchstart', (e) => {
    touchStartX = e.touches[0].clientX;
    touchStartY = e.touches[0].clientY;
  });

  document.addEventListener('touchend', (e) => {
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;

    const dx = touchEndX - touchStartX;
    const dy = touchEndY - touchStartY;

    if (Math.abs(dx) > Math.abs(dy)) {
      if (dx > 50) handleMove('right');
      else if (dx < -50) handleMove('left');
    } else {
      if (dy > 50) handleMove('down');
      else if (dy < -50) handleMove('up');
    }
  });

  // 初始化游戏
  newGame();
</script>
{% endraw %}

