<script>
  const breakoutCanvas = document.getElementById('gameCanvas');
  const breakoutCtx = breakoutCanvas.getContext('2d');

  let paddle = {
    width: 100,
    height: 15,
    x: 350,
    speed: 8
  };

  let ball = {
    x: 400,
    y: 550,
    radius: 8,
    dx: 4,
    dy: -4,
