  function initBricks() {
    bricks = [];
    for (let c = 0; c < brickColumnCount; c++) {
      bricks[c] = [];
      for (let r = 0; r < brickRowCount; r++) {
        bricks[c][r] = { 
          x: 0, 
          y: 0, 
          status: 1,
          color: brickColors[r],
          points: brickPoints[r]
        };
      }
    }
  }

  function drawPaddle() {
    breakoutCtx.beginPath();
    breakoutCtx.rect(paddle.x, breakoutCanvas.height - paddle.height - 10, paddle.width, paddle.height);
    breakoutCtx.fillStyle = '#ecf0f1';
    breakoutCtx.fill();
    breakoutCtx.closePath();
  }

  function drawBall() {
    breakoutCtx.beginPath();
    breakoutCtx.arc(ball.x, ball.y, ball.radius, 0, Math.PI * 2);
    breakoutCtx.fillStyle = '#ecf0f1';
    breakoutCtx.fill();
    breakoutCtx.closePath();
  }

  function drawBricks() {
    for (let c = 0; c < brickColumnCount; c++) {
      for (let r = 0; r < brickRowCount; r++) {
        if (bricks[c][r].status === 1) {
          const brickX = c * (brickWidth + brickPadding) + brickOffsetLeft;
          const brickY = r * (brickHeight + brickPadding) + brickOffsetTop;
          bricks[c][r].x = brickX;
          bricks[c][r].y = brickY;

          breakoutCtx.beginPath();
          breakoutCtx.rect(brickX, brickY, brickWidth, brickHeight);
          breakoutCtx.fillStyle = bricks[c][r].color;
          breakoutCtx.fill();
          breakoutCtx.strokeStyle = 'rgba(255,255,255,0.3)';
          breakoutCtx.stroke();
          breakoutCtx.closePath();
        }
      }
    }
  }

  function collisionDetection() {
    for (let c = 0; c < brickColumnCount; c++) {
      for (let r = 0; r < brickRowCount; r++) {
        const b = bricks[c][r];
        if (b.status === 1) {
          if (ball.x > b.x && ball.x < b.x + brickWidth && 
              ball.y > b.y && ball.y < b.y + brickHeight) {
            ball.dy = -ball.dy;
            b.status = 0;
            score += b.points;
            document.getElementById('score').textContent = score;

            if (score > highScore) {
              highScore = score;
              document.getElementById('highScore').textContent = highScore;
              localStorage.setItem('breakoutHighScore', highScore);
            }

            // 检查是否全部消除
            let allDestroyed = true;
            for (let i = 0; i < brickColumnCount; i++) {
              for (let j = 0; j < brickRowCount; j++) {
                if (bricks[i][j].status === 1) {
                  allDestroyed = false;
                  break;
                }
              }
            }

            if (allDestroyed) {
              gameWin();
            }
          }
        }
      }
    }
  }

