<script>
  let board = [];
  let rows = 9;
  let cols = 9;
  let mines = 10;
  let minesLeft = 10;
  let gameOver = false;
  let firstClick = true;
  let timer = 0;
  let timerInterval = null;

  const difficulties = {
    easy: { rows: 9, cols: 9, mines: 10 },
    medium: { rows: 16, cols: 16, mines: 40 },
    hard: { rows: 16, cols: 30, mines: 99 }
  };

  function initBoard() {
    board = [];
    for (let i = 0; i < rows; i++) {
      board[i] = [];
      for (let j = 0; j < cols; j++) {
        board[i][j] = {
          mine: false,
          revealed: false,
          flagged: false,
          count: 0
        };
      }
    }
  }

  function placeMines(excludeRow, excludeCol) {
    let placed = 0;
    while (placed < mines) {
      const r = Math.floor(Math.random() * rows);
      const c = Math.floor(Math.random() * cols);

      // 排除第一次点击的位置及其周围
      if (Math.abs(r - excludeRow) <= 1 && Math.abs(c - excludeCol) <= 1) {
        continue;
      }

      if (!board[r][c].mine) {
        board[r][c].mine = true;
        placed++;
      }
    }

    // 计算每个格子周围的地雷数
    for (let i = 0; i < rows; i++) {
      for (let j = 0; j < cols; j++) {
        if (!board[i][j].mine) {
          board[i][j].count = countAdjacentMines(i, j);
        }
      }
    }
  }

  function countAdjacentMines(row, col) {
    let count = 0;
    for (let i = -1; i <= 1; i++) {
      for (let j = -1; j <= 1; j++) {
        const r = row + i;
        const c = col + j;
        if (r >= 0 && r < rows && c >= 0 && c < cols && board[r][c].mine) {
          count++;
        }
      }
    }
    return count;
  }

  function renderBoard() {
    const gameBoard = document.getElementById('gameBoard');
    gameBoard.innerHTML = '';
    gameBoard.style.gridTemplateColumns = `repeat(${cols}, 30px)`;

    for (let i = 0; i < rows; i++) {
      for (let j = 0; j < cols; j++) {
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.dataset.row = i;
        cell.dataset.col = j;

        if (board[i][j].revealed) {
          cell.classList.add('revealed');
          if (board[i][j].mine) {
            cell.classList.add('mine');
            cell.textContent = '💣';
          } else if (board[i][j].count > 0) {
            cell.textContent = board[i][j].count;
            cell.dataset.number = board[i][j].count;
          }
        } else if (board[i][j].flagged) {
          cell.classList.add('flagged');
        }

        cell.addEventListener('click', () => handleClick(i, j));
        cell.addEventListener('contextmenu', (e) => {
          e.preventDefault();
          handleRightClick(i, j);
        });

        gameBoard.appendChild(cell);
      }
    }
  }

  function handleClick(row, col) {
    if (gameOver || board[row][col].flagged || board[row][col].revealed) {
      return;
    }

    if (firstClick) {
      firstClick = false;
      placeMines(row, col);
      startTimer();
    }

    if (board[row][col].mine) {
      revealAllMines();
      endGame(false);
    } else {
      revealCell(row, col);
      checkWin();
    }

    renderBoard();
  }

  function handleRightClick(row, col) {
    if (gameOver || board[row][col].revealed) {
      return;
    }

    board[row][col].flagged = !board[row][col].flagged;
    minesLeft += board[row][col].flagged ? -1 : 1;
    document.getElementById('minesLeft').textContent = minesLeft;

    renderBoard();
  }

  function revealCell(row, col) {
    if (row < 0 || row >= rows || col < 0 || col >= cols) {
      return;
    }

    if (board[row][col].revealed || board[row][col].flagged) {
      return;
    }

    board[row][col].revealed = true;

    if (board[row][col].count === 0 && !board[row][col].mine) {
      for (let i = -1; i <= 1; i++) {
        for (let j = -1; j <= 1; j++) {
          revealCell(row + i, col + j);
        }
      }
    }
  }

  function revealAllMines() {
    for (let i = 0; i < rows; i++) {
      for (let j = 0; j < cols; j++) {
        if (board[i][j].mine) {
          board[i][j].revealed = true;
        }
      }
    }
  }

  function checkWin() {
    let unrevealedSafe = 0;
    for (let i = 0; i < rows; i++) {
      for (let j = 0; j < cols; j++) {
        if (!board[i][j].mine && !board[i][j].revealed) {
          unrevealedSafe++;
        }
      }
    }

    if (unrevealedSafe === 0) {
      endGame(true);
    }
  }

  function startTimer() {
    timer = 0;
    timerInterval = setInterval(() => {
      timer++;
      document.getElementById('timer').textContent = timer;
    }, 1000);
  }

  function stopTimer() {
    if (timerInterval) {
      clearInterval(timerInterval);
      timerInterval = null;
    }
  }

  function endGame(won) {
    gameOver = true;
    stopTimer();

    const gameOverDiv = document.getElementById('gameOver');
    const title = document.getElementById('gameOverTitle');
    const text = document.getElementById('gameOverText');

    if (won) {
      title.textContent = '🎉 恭喜!';
      text.textContent = `你用了 ${timer} 秒完成了游戏!`;
    } else {
      title.textContent = '游戏结束!';
      text.textContent = '踩到地雷了!';
    }

    gameOverDiv.classList.remove('hidden');
  }

  function newGame() {
    const difficulty = document.getElementById('difficulty').value;
    const config = difficulties[difficulty];

    rows = config.rows;
    cols = config.cols;
    mines = config.mines;
    minesLeft = mines;
    gameOver = false;
    firstClick = true;

    document.getElementById('minesLeft').textContent = minesLeft;
    document.getElementById('timer').textContent = '0';
    document.getElementById('gameOver').classList.add('hidden');

    stopTimer();
    initBoard();
    renderBoard();
  }

  // 初始化游戏
  newGame();
</script>
