      " #  #  #",
      " #######"
    ],
    [
      "##########",
      "#        #",
      "# ###### #",
      "# #....# #",
      "# #....# #",
      "# ##$$## #",
      "#  $@@$  #",
      "#  $  $  #",
      "##########"
    ]
  ];

  let currentLevel = 0;
  let playerPos = { x: 0, y: 0 };
  let boxes = [];
  let targets = [];
  let moves = 0;
  let map = [];

  function parseLevel(levelData) {
    map = [];
    boxes = [];
    targets = [];

    const maxWidth = Math.max(...levelData.map(row => row.length));

    for (let y = 0; y < levelData.length; y++) {
      const row = [];
      for (let x = 0; x < maxWidth; x++) {
        const char = levelData[y][x] || ' ';

        switch (char) {
          case WALL:
            row.push(WALL);
            break;
          case TARGET:
            row.push(TARGET);
            targets.push({ x, y });
            break;
          case BOX:
            row.push(FLOOR);
            boxes.push({ x, y });
            break;
          case BOX_ON_TARGET:
            row.push(TARGET);
            targets.push({ x, y });
            boxes.push({ x, y });
            break;
          case PLAYER:
            row.push(FLOOR);
            playerPos = { x, y };
            break;
          case PLAYER_ON_TARGET:
            row.push(TARGET);
            targets.push({ x, y });
            playerPos = { x, y };
            break;
          default:
            row.push(FLOOR);
        }
      }
      map.push(row);
    }
  }

  function render() {
    const gameBoard = document.getElementById('gameBoard');
    gameBoard.innerHTML = '';

    gameBoard.style.gridTemplateColumns = `repeat(${map[0].length}, 50px)`;
    gameBoard.style.gridTemplateRows = `repeat(${map.length}, 50px)`;

    for (let y = 0; y < map.length; y++) {
      for (let x = 0; x < map[y].length; x++) {
        const cell = document.createElement('div');
        cell.className = 'cell';

        const isBox = boxes.some(box => box.x === x && box.y === y);
        const isTarget = targets.some(target => target.x === x && target.y === y);
        const isPlayer = playerPos.x === x && playerPos.y === y;

        if (map[y][x] === WALL) {
          cell.classList.add('wall');
          cell.textContent = '🧱';
        } else if (isPlayer) {
          cell.classList.add(isTarget ? 'target' : 'floor');
          cell.textContent = '😊';
        } else if (isBox) {
          cell.classList.add(isTarget ? 'box-on-target' : 'box');
          cell.textContent = isTarget ? '✅' : '📦';
        } else if (isTarget) {
          cell.classList.add('target');
          cell.textContent = '⭕';
        } else {
          cell.classList.add('floor');
        }

        gameBoard.appendChild(cell);
      }
    }

    document.getElementById('level').textContent = currentLevel + 1;
    document.getElementById('moves').textContent = moves;
  }

  function canMove(x, y) {
    if (x < 0 || y < 0 || y >= map.length || x >= map[0].length) {
      return false;
    }
    return map[y][x] !== WALL;
  }

  function getBoxAt(x, y) {
    return boxes.findIndex(box => box.x === x && box.y === y);
  }

  function move(dx, dy) {
    const newX = playerPos.x + dx;
    const newY = playerPos.y + dy;

    if (!canMove(newX, newY)) {
      return;
    }

    const boxIndex = getBoxAt(newX, newY);

    if (boxIndex !== -1) {
      const newBoxX = newX + dx;
      const newBoxY = newY + dy;

      if (!canMove(newBoxX, newBoxY) || getBoxAt(newBoxX, newBoxY) !== -1) {
        return;
      }

      boxes[boxIndex].x = newBoxX;
      boxes[boxIndex].y = newBoxY;
    }

    playerPos.x = newX;
    playerPos.y = newY;
    moves++;

    render();
    checkWin();
  }

  function checkWin() {
    const allBoxesOnTargets = boxes.every(box =>
      targets.some(target => target.x === box.x && target.y === box.y)
    );

    if (allBoxesOnTargets) {
      setTimeout(() => {
        if (currentLevel < levels.length - 1) {
          alert(`恭喜过关！点击"下一关"继续挑战！`);
        } else {
          alert(`恭喜你通关所有关卡！`);
        }
      }, 100);
    }
  }

  function loadLevel(levelIndex) {
    if (levelIndex < 0 || levelIndex >= levels.length) {
      return;
    }

    currentLevel = levelIndex;
    moves = 0;
    parseLevel(levels[currentLevel]);
    render();
  }

  function resetLevel() {
    moves = 0;
    parseLevel(levels[currentLevel]);
    render();
  }

  function prevLevel() {
    if (currentLevel > 0) {
      loadLevel(currentLevel - 1);
    }
  }

  function nextLevel() {
    if (currentLevel < levels.length - 1) {
      loadLevel(currentLevel + 1);
    }
  }

  // 键盘控制
  document.addEventListener('keydown', (e) => {
    switch (e.key) {
      case 'ArrowUp':
      case 'w':
      case 'W':
        move(0, -1);
        e.preventDefault();
        break;
      case 'ArrowDown':
      case 's':
      case 'S':
        move(0, 1);
        e.preventDefault();
        break;
      case 'ArrowLeft':
      case 'a':
      case 'A':
        move(-1, 0);
        e.preventDefault();
        break;
      case 'ArrowRight':
      case 'd':
      case 'D':
        move(1, 0);
        e.preventDefault();
        break;
    }
  });

  // 初始化游戏
  loadLevel(0);
</script>
